from abc import ABC, abstractmethod

class Btn(ABC):
    @abstractmethod
    def paint(self): ...

class WinBtn(Btn):
    def paint(self):
        return "win"

class Factory(ABC):
    @abstractmethod
    def make(self): ...

class WinFactory(Factory):
    def make(self):
        return WinBtn()

def client(f):
    return f.make().paint()

print(client(WinFactory()))

